3201	// Lode-collision case — exercises the cloud-side touchmark collision guard
3202	// (rbgjl01-ensconce-capture.sh). The guard cannot fire under natural minting:
3203	// each ensconce mints a fresh second-grained stamp, so two CLI captures land on
3204	// distinct touchmarks. We pin the stamp via the buo tweak channel
3205	// (RBTDRC_ENSCONCE_STAMP_TWEAK_NAME) to drive both captures onto ONE touchmark.
3206	//
3207	// Sequence: (1) ensconce busybox naturally -> mint touchmark S, read it back;
3208	// (2) ensconce busybox pinned to S -> identical digest, guard's idempotent
3209	// branch, exit 0; (3) ensconce debian pinned to S -> different digest under the
3210	// same touchmark, guard's collision branch, host exit non-zero; (4) banish S.
3211	//
3212	// The collision verdict rests on the HOST EXIT CODE: the guard's "touchmark
3213	// collision" message lands in Cloud Logging (CLOUD_LOGGING_ONLY), not host
3214	// stdout, but a cloud build FAILURE propagates to a non-zero rbw-lE exit
3215	// (rbfcb_BuildHost.sh: status != SUCCESS -> buc_die). The idempotent step (2) is
3216	// the positive control: the identical pipeline on the same pinned touchmark
3217	// SUCCEEDS for the same base, so step (3)'s failure isolates to the differing
3218	// digest — the collision branch — not debian-specific infra. Both vessels carry
3219	// the same yoked reliquary, so host-side skopeo resolution is identical.
3220	fn rbtdrc_lode_collision(dir: &Path) -> rbtdre_Verdict {
3221	    rbtdrc_with_ctx(|ctx| {
3222	        let busybox_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
3223	        let deb_dir = RBTDRC_DEB_VESSEL_DIR;
3224	        for vd in &[busybox_dir, deb_dir] {
3225	            if !ctx.project_root().join(vd).is_dir() {
3226	                return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vd));
3227	            }
3228	        }
3229	
3230	        // Step 1: ensconce busybox naturally; read back the minted touchmark S.
3231	        let _ = std::fs::write(dir.join("01-ensconce-fresh.txt"), "ensconcing busybox (fresh, natural mint)");
3232	        let fresh = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[busybox_dir], &[]) {
3233	            Ok(r) if r.exit_code == 0 => r,
3234	            Ok(r) => return rbtdre_Verdict::Fail(format!("fresh ensconce failed (exit {})\n{}", r.exit_code, r.stderr)),
3235	            Err(e) => return rbtdre_Verdict::Fail(format!("fresh ensconce invocation: {}", e)),
3236	        };
3237	        let _ = std::fs::write(dir.join("01-ensconce-fresh-stdout.txt"), &fresh.stdout);
3238	        let touchmark = match rbtdri_read_burv_fact(&fresh, RBTDRC_FACT_LODE_TOUCHMARK) {
3239	            Ok(v) => v,
3240	            Err(e) => return rbtdre_Verdict::Fail(format!("read touchmark fact: {}", e)),
3241	        };
3242	        let _ = std::fs::write(dir.join("02-touchmark.txt"), &touchmark);
3243	
3244	        let pin = &[
3245	            ("BURE_TWEAK_NAME", RBTDRC_ENSCONCE_STAMP_TWEAK_NAME),
3246	            ("BURE_TWEAK_VALUE", touchmark.as_str()),
3247	        ];
3248	
3249	        // Step 2 (positive control): ensconce busybox pinned to S — identical
3250	        // digest under the same touchmark — guard's idempotent branch — must PASS.
3251	        let _ = std::fs::write(dir.join("03-ensconce-idempotent.txt"), "ensconcing busybox pinned to S (identical digest)");
3252	        let idem = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[busybox_dir], pin) {
3253	            Ok(r) if r.exit_code == 0 => r,
3254	            Ok(r) => return rbtdre_Verdict::Fail(format!(
3255	                "idempotent ensconce (same base, same touchmark) should pass but failed (exit {})\n{}",
3256	                r.exit_code, r.stderr)),
3257	            Err(e) => return rbtdre_Verdict::Fail(format!("idempotent ensconce invocation: {}", e)),
3258	        };
3259	        let _ = std::fs::write(dir.join("03-ensconce-idempotent-stdout.txt"), &idem.stdout);
3260	
3261	        // Step 3: ensconce debian pinned to S — different digest under the same
3262	        // touchmark — guard's collision branch — host exit must be non-zero.
3263	        let _ = std::fs::write(dir.join("04-ensconce-collision.txt"), "ensconcing debian pinned to S (different digest -> collision)");
3264	        let collision = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[deb_dir], pin) {
3265	            Ok(r) => r,
3266	            Err(e) => return rbtdre_Verdict::Fail(format!("collision ensconce invocation: {}", e)),
3267	        };
3268	        let _ = std::fs::write(dir.join("04-ensconce-collision-stdout.txt"), &collision.stdout);
3269	        let _ = std::fs::write(dir.join("04-ensconce-collision-stderr.txt"), &collision.stderr);
3270	        if collision.exit_code == 0 {
3271	            return rbtdre_Verdict::Fail(format!(
3272	                "collision ensconce (different base, same touchmark {}) should fail loud but exited 0\nstdout:\n{}",
3273	                touchmark, collision.stdout));
3274	        }
3275	
3276	        // Step 4: banish S — cleanup (removes the busybox Lode steps 1-2 left;
