3278	        let _ = std::fs::write(dir.join("05-banish.txt"), "banishing");
3279	        match rbtdri_invoke_global(
3280	            ctx,
3281	            RBTDGC_BANISH_LODE,
3282	            &[&touchmark],
3283	            &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
3284	        ) {
3285	            Ok(r) if r.exit_code == 0 => {}
3286	            Ok(r) => return rbtdre_Verdict::Fail(format!("banish failed (exit {})\n{}", r.exit_code, r.stderr)),
3287	            Err(e) => return rbtdre_Verdict::Fail(format!("banish invocation: {}", e)),
3288	        }
3289	
3290	        // Step 5: divine enumerate no longer shows S — registry restored.
3291	        let final_divine = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
3292	            Ok(r) if r.exit_code == 0 => r,
3293	            Ok(r) => return rbtdre_Verdict::Fail(format!("final divine failed (exit {})\n{}", r.exit_code, r.stderr)),
3294	            Err(e) => return rbtdre_Verdict::Fail(format!("final divine invocation: {}", e)),
3295	        };
3296	        let _ = std::fs::write(dir.join("06-divine-final.txt"), &final_divine.stdout);
3297	        if final_divine.stdout.contains(&touchmark) {
3298	            return rbtdre_Verdict::Fail(format!(
3299	                "final divine still shows banished touchmark {} — cleanup failed\nstdout:\n{}",
3300	                touchmark, final_divine.stdout));
3301	        }
3302	
3303	        let _ = std::fs::write(dir.join("07-passed.txt"), "passed");
3304	        rbtdre_Verdict::Pass
3305	    })
3306	}
