    return rbtdre_Verdict::Fail(format!(
        "post-jettison list missing sibling member '{}' — jettison damaged the Lode\nstdout:\n{}",
        RBTDRC_RELIQUARY_TAG_GCLOUD, post_list.stdout
    ));
}

